<script setup lang="ts">import {ref} from'vue';import InputNumber from'primevue/inputnumber';import Button from'primevue/button';import Card from'primevue/card';import Tag from'primevue/tag';import Message from'primevue/message';import DataTable from'primevue/datatable';import Column from'primevue/column';import Dialog from'primevue/dialog';import {useToast}from'primevue/usetoast';import {postDraftReportsApi}from'../../infrastructure/PostDraftReportsApi';import type{PostDraftReportSummary}from'../../domain/PostDraftReportTypes';import{getErrorMessage}from'@/modules/postDraftMetrics/application/useWrMetricManagement';const teamId=ref<number|null>(null),draftYear=ref(new Date().getFullYear()),report=ref<PostDraftReportSummary|null>(null),history=ref<PostDraftReportSummary[]>([]),selected=ref<PostDraftReportSummary|null>(null),historyVisible=ref(false),loading=ref(false),error=ref('');const toast=useToast();async function run(kind:'get'|'preview'|'finalize'){if(!teamId.value)return;loading.value=true;error.value='';try{report.value=await postDraftReportsApi[kind](teamId.value,draftYear.value);toast.add({severity:'success',summary:kind==='finalize'?'Finalized':'Loaded',detail:kind==='finalize'?'Immutable report snapshot created.':'Report loaded.',life:3000})}catch(e:unknown){error.value=getErrorMessage(e)}finally{loading.value=false}}async function openHistory(){if(!teamId.value)return;loading.value=true;try{history.value=await postDraftReportsApi.history(teamId.value,draftYear.value);historyVisible.value=true}catch(e:unknown){error.value=getErrorMessage(e)}finally{loading.value=false}}function missing(r:PostDraftReportSummary){const v=r.missingDataIndicators??r.missingData;return Array.isArray(v)?v.length:0}</script>
<template><main class="page"><header><div><p class="eyebrow">Immutable Evaluation Snapshots</p><h1>Post-Draft Reports</h1><p>Preview live source data or open immutable finalized report versions.</p></div></header><Card><template #content><div class="filters"><label>Team ID<InputNumber v-model="teamId" :useGrouping="false"/></label><label>Draft Year<InputNumber v-model="draftYear" :useGrouping="false"/></label><Button label="Load Current" @click="run('get')"/><Button label="Preview Live" icon="pi pi-eye" @click="run('preview')"/><Button label="Finalize Snapshot" icon="pi pi-lock" severity="success" @click="run('finalize')"/><Button label="History" icon="pi pi-history" @click="openHistory"/></div></template></Card><Message v-if="error" severity="error" :closable="false">{{error}}</Message><Card v-if="report"><template #title><div class="title"><span>Report</span><Tag :value="report.status??'LIVE'" :severity="report.status==='FINALIZED'?'success':'warning'"/></div></template><template #content><div class="facts"><div><span>Report Version</span><strong>{{report.reportVersion??report.version??'Live'}}</strong></div><div><span>Model Version</span><strong>{{report.modelVersion??'Unknown'}}</strong></div><div><span>Finalized At</span><strong>{{report.finalizedAt??'Not finalized'}}</strong></div><div><span>Data Confidence</span><strong>{{report.dataConfidence??'Unknown'}}</strong></div><div><span>Missing Data</span><strong>{{missing(report)}}</strong></div><div><span>Input Hash</span><strong class="hash">{{report.inputHash??'Live input'}}</strong></div></div><Message :severity="report.status==='FINALIZED'?'success':'warn'" :closable="false">{{report.status==='FINALIZED'?'This is an immutable finalized snapshot. Later metric edits do not change it.':'This is a live preview and may change when source data changes.'}}</Message><details v-if="report.wrMetricProvenance"><summary>WR Metric Provenance</summary><pre>{{JSON.stringify(report.wrMetricProvenance,null,2)}}</pre></details></template></Card><Dialog v-model:visible="historyVisible" modal header="Finalized Report History" :style="{width:'min(70rem,96vw)'}"><DataTable :value="history" selectionMode="single" v-model:selection="selected" dataKey="id"><Column field="reportVersion" header="Version"/><Column field="modelVersion" header="Model"/><Column field="finalizedAt" header="Finalized"/><Column field="dataConfidence" header="Confidence"/><Column header="Missing"><template #body="{data}">{{missing(data)}}</template></Column></DataTable><template #footer><Button label="Open Selected Version" :disabled="!selected" @click="report=selected;historyVisible=false"/></template></Dialog></main></template><style scoped>.page{display:grid;gap:1rem;padding:1rem}.page header{background:var(--surface-card);padding:1rem;border-radius:1rem}.eyebrow{margin:0;text-transform:uppercase;color:var(--text-color-secondary);font-size:.75rem}.filters,.title{display:flex;gap:.75rem;align-items:end;flex-wrap:wrap}.filters label{display:grid;gap:.35rem}.facts{display:grid;grid-template-columns:repeat(auto-fit,minmax(12rem,1fr));gap:1rem;margin-bottom:1rem}.facts span{display:block;color:var(--text-color-secondary);font-size:.8rem}.hash{overflow-wrap:anywhere}pre{white-space:pre-wrap;max-height:30rem;overflow:auto}</style>
